    togglePurchaseSelect: function(id) {
        const selected = store.state.selectedPurchases || [];
        const idx = selected.indexOf(id);
        if (idx >= 0) selected.splice(idx, 1); else selected.push(id);
        store.setState({ selectedPurchases: [...selected] });
        renderApp(pages.transactions());
    },

    toggleAllPurchases: function(checked) {
        if (checked) {
            const purchases = store.state.purchases || [];
            store.setState({ selectedPurchases: purchases.map(p => p.id) });
        } else {
            store.setState({ selectedPurchases: [] });
        }
        renderApp(pages.transactions());
    },

    bulkCategorizePurchases: async function(category) {
        if (!category) return;
        const selected = store.state.selectedPurchases || [];
        if (selected.length === 0) { toast.error('No purchases selected'); return; }
        toast.info(`Categorizing ${selected.length} purchases as "${category}"...`);
        let updated = 0;
        for (const id of selected) {
            try {
                await api.put('/financials/purchases/' + id, { category });
                updated++;
            } catch { /* skip failures */ }
        }
        store.setState({ selectedPurchases: [] });
        await handlers.loadPurchases();
        toast.success(`Updated ${updated} of ${selected.length} purchases to "${category}"`);
        renderApp(pages.transactions());
    },

