    saveRecurringTemplate: async function() {
        const description = document.getElementById('recurring-desc')?.value;
        const amount = parseFloat(document.getElementById('recurring-amount')?.value);
        const accountId = document.getElementById('recurring-account')?.value;
        const category = document.getElementById('recurring-category')?.value;
        const frequency = document.getElementById('recurring-frequency')?.value;

        if (!description || !amount) {
            toast.error('Description and amount are required');
            return;
        }

        try {
            await api.post('/financials/recurring-templates', { description, amount, accountId, category, frequency });
            toast.success('Recurring template created');
            handlers.showRecurringTemplates();
        } catch (err) {
            toast.error('Failed to create template');
        }
    },

    executeRecurringTemplate: async function(templateId) {
        try {
            await api.post(`/financials/recurring-templates/${templateId}/execute`);
            toast.success('Recurring transaction created');
            handlers.showRecurringTemplates();
        } catch (err) {
            toast.error('Failed to execute template');
        }
    },

    deleteRecurringTemplate: async function(templateId) {
        if (!await modals.confirm('Delete this recurring template?', { title: 'Delete Template', confirmText: 'Delete', danger: true })) return;
        try {
            await api.delete(`/financials/recurring-templates/${templateId}`);
            toast.success('Template deleted');
            handlers.showRecurringTemplates();
        } catch (err) {
            toast.error('Failed to delete template');
        }
    },

    // Receipt Attachment Modal,

    showAttachReceiptModal: function(txId) {
        modals.show(`
            <div class="modal-header">
                <h2 class="modal-title">${components.icon('paperclip', 20)} Attach Receipt</h2>
                <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('close')}</button>
            </div>
            <div class="modal-body">
                <div class="form-group">
                    <label class="form-label">Select receipt image (max 2MB)</label>
                    <input type="file" class="form-input" id="receipt-file-input" accept="image/*,.pdf" onchange="
                        const file = this.files[0];
                        if (file && file.size > 2 * 1024 * 1024) {
                            toast.error('File too large (max 2MB)');
                            this.value = '';
                            return;
                        }
                        if (file) {
                            document.getElementById('receipt-file-name').textContent = file.name + ' (' + (file.size / 1024).toFixed(1) + ' KB)';
                        }
                    ">
                    <p id="receipt-file-name" style="font-size: 12px; color: var(--gray-500); margin-top: 4px;"></p>
                </div>
                <div id="receipt-preview" style="margin-top: 8px;"></div>
            </div>
            <div class="modal-footer">
                <button class="btn btn-secondary" onclick="modals.close()">Cancel</button>
                <button class="btn btn-primary" onclick="handlers.uploadReceipt('${txId}')">Upload</button>
            </div>
        `);
    },

    uploadReceipt: async function(txId) {
        const fileInput = document.getElementById('receipt-file-input');
        const file = fileInput?.files?.[0];
        if (!file) {
            toast.error('Please select a file');
            return;
        }

        try {
            const reader = new FileReader();
            reader.onload = async function(e) {
                const base64 = e.target.result.split(',')[1];
                try {
                    await api.post(`/financials/transactions/${txId}/attachments`, {
                        fileName: file.name,
                        fileType: file.type,
                        fileData: base64
                    });
                    toast.success('Receipt attached');
                    modals.close();
                } catch (err) {
                    toast.error('Upload failed: ' + (err.message || 'Unknown error'));
                }
            };
            reader.readAsDataURL(file);
        } catch (err) {
            toast.error('Failed to read file');
        }
    },

