    savePurchaseOrder: function(e) {
        e.preventDefault();
        const form = e.target;
        const suppliers = store.state.suppliers || [
            { id: '1', name: 'ThriftWholesale' }, { id: '2', name: 'VintageSupply Co' },
            { id: '3', name: 'BulkClothing Direct' }, { id: '4', name: 'Designer Liquidators' }
        ];
        const supplier = suppliers.find(s => s.id === form.supplierId.value);
        const poNum = 'PO-' + Date.now().toString().slice(-6);
        const newPO = {
            id: 'po_' + Date.now(),
            number: poNum,
            supplierId: form.supplierId.value,
            supplierName: supplier?.name || 'Unknown',
            itemCount: parseInt(form.itemCount.value) || 1,
            total: parseFloat(form.total.value) || 0,
            notes: form.notes.value,
            status: 'pending',
            created_at: new Date().toISOString()
        };
        const purchaseOrders = [...(store.state.purchaseOrders || []), newPO];
        store.setState({ purchaseOrders });
        toast.success('Purchase order ' + poNum + ' created');
        modals.close();
        renderApp(pages.suppliers());
    },

