    // Market Intel handlers,

    refreshMarketIntel: async function() {
        toast.info('Refreshing market intelligence...');
        try {
            await handlers.loadMarketIntel();
            toast.success('Market data refreshed');
            if (store.state.currentPage === 'market-intel') {
                renderApp(pages.marketIntel());
            }
        } catch (err) {
            toast.error('Failed to refresh data');
        }
    },

    exportMarketIntel: function() {
        const competitors = store.state.competitors || [];
        const insights = store.state.marketInsights || [];
        let csv = 'Name,Platform,URL,Items,Avg Price,Tracked Since,Notes\n';
        competitors.forEach(c => {
            csv += `"${(c.name || '').replace(/"/g, '""')}","${c.platform || ''}","${c.url || ''}",${c.item_count || 0},${(c.avg_price || 0).toFixed(2)},"${c.tracked_since || ''}","${(c.notes || '').replace(/"/g, '""')}"\n`;
        });
        if (insights.length > 0) {
            csv += '\nInsight,Category,Confidence,Date\n';
            insights.forEach(i => {
                csv += `"${(i.title || i.text || '').replace(/"/g, '""')}","${i.category || ''}","${i.confidence || ''}","${i.date || ''}"\n`;
            });
        }
        const blob = new Blob([csv], { type: 'text/csv' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `market_intel_export_${new Date().toISOString().slice(0, 10)}.csv`;
        a.click();
        URL.revokeObjectURL(url);
        toast.success(`Exported ${competitors.length} competitors and ${insights.length} insights`);
    },

