    // ==========================================
    // Resources Section Handlers
    // ==========================================

    // Settings handlers,

    setSettingsTab: function(tab) {
        store.setState({ settingsTab: tab, settingsChanged: false });
        window.history.replaceState({}, '', `#settings/${tab}`);
        renderApp(pages.settings());
    },

    // Settings search handler,

    settingsSearch: function(query) {
        const resultsEl = document.getElementById('settings-search-results');
        if (!resultsEl) return;

        if (!query || query.trim().length === 0) {
            resultsEl.style.display = 'none';
            resultsEl.innerHTML = '';
            return;
        }

        const searchMap = [
            { terms: ['name', 'email', 'display', 'timezone', 'avatar', 'profile', 'personal'], tab: 'profile', label: 'Personal Information', icon: 'user' },
            { terms: ['security', 'password', '2fa', 'two-factor', 'login'], tab: 'profile', label: 'Security Overview', icon: 'lock' },
            { terms: ['theme', 'dark mode', 'light mode', 'accent', 'color', 'appearance'], tab: 'appearance', label: 'Theme', icon: 'sun' },
            { terms: ['density', 'font size', 'compact', 'comfortable', 'display'], tab: 'appearance', label: 'Display Settings', icon: 'sun' },
            { terms: ['keyboard', 'shortcuts', 'hotkey'], tab: 'appearance', label: 'Keyboard Shortcuts', icon: 'sun' },
            { terms: ['notification', 'email alerts', 'push', 'quiet hours', 'digest', 'alert'], tab: 'notifications', label: 'Notifications', icon: 'bell' },
            { terms: ['integration', 'ebay', 'mercari', 'poshmark', 'whatnot', 'depop', 'api key', 'connected', 'platform'], tab: 'integrations', label: 'Integrations', icon: 'link' },
            { terms: ['shipping', 'sku', 'webhook', 'affiliate', 'listing defaults', 'watermark', 'tools'], tab: 'tools', label: 'Tools & Defaults', icon: 'tool' },
            { terms: ['billing', 'plan', 'subscription', 'payment', 'pricing', 'upgrade', 'invoice'], tab: 'billing', label: 'Billing & Plans', icon: 'credit-card' },
            { terms: ['export', 'import', 'backup', 'privacy', 'delete account', 'data', 'cache', 'cleanup', 'activity', 'retention'], tab: 'data', label: 'Data Management', icon: 'database' },
        ];

        const q = query.toLowerCase().trim();
        const matches = searchMap.filter(item =>
            item.terms.some(t => t.includes(q)) || item.label.toLowerCase().includes(q) || item.tab.includes(q)
        );

        if (matches.length === 0) {
            resultsEl.innerHTML = '<div style="padding:12px 16px; color:var(--gray-500); font-size:13px;">No matching settings found</div>';
            resultsEl.style.display = 'block';
            return;
        }

        resultsEl.innerHTML = matches.map(m => `
            <div class="settings-search-result" onclick="handlers.setSettingsTab('${m.tab}'); document.getElementById('settings-search-input').value=''; document.getElementById('settings-search-results').style.display='none';"
                style="padding:10px 16px; cursor:pointer; display:flex; align-items:center; gap:10px; border-bottom:1px solid var(--gray-100);"
                onmouseover="this.style.background='var(--gray-50)'" onmouseout="this.style.background='transparent'">
                ${components.icon(m.icon, 16)}
                <div>
                    <div style="font-size:13px; font-weight:500;">${m.label}</div>
                    <div style="font-size:11px; color:var(--gray-500); text-transform:capitalize;">${m.tab} tab</div>
                </div>
            </div>
        `).join('');
        resultsEl.style.display = 'block';
    },

    // Data Retention Handlers,

    updateRetentionSetting: function(setting, value) {
        const currentSettings = store.state.dataRetention || {
            completedOrders: '365',
            soldItems: '180',
            analyticsData: '90',
            notifications: '30',
            automationLogs: '30',
            autoCleanup: false
        };
        store.setState({
            dataRetention: { ...currentSettings, [setting]: value }
        });
        toast.success(`Retention setting updated`);
    },

    previewRetentionCleanup: function() {
        const settings = store.state.dataRetention || {};

        // Calculate mock data that would be cleaned up
        const now = Date.now();
        const getDataCounts = (category, days) => {
            if (days === 'forever') return 0;
            const daysNum = parseInt(days);
            // Mock calculation
            return Math.floor(Math.random() * 50) + (daysNum < 90 ? 20 : 5);
        };

        const previewData = [
            { category: 'Completed Orders', count: getDataCounts('orders', settings.completedOrders || '365'), retention: settings.completedOrders || '365' },
            { category: 'Sold Items', count: getDataCounts('sold', settings.soldItems || '180'), retention: settings.soldItems || '180' },
            { category: 'Analytics Records', count: getDataCounts('analytics', settings.analyticsData || '90'), retention: settings.analyticsData || '90' },
            { category: 'Notifications', count: getDataCounts('notifications', settings.notifications || '30'), retention: settings.notifications || '30' },
            { category: 'Automation Logs', count: getDataCounts('logs', settings.automationLogs || '30'), retention: settings.automationLogs || '30' }
        ];

        const totalItems = previewData.reduce((sum, d) => sum + d.count, 0);
        const formatRetention = (value) => value === 'forever' ? 'Keep forever' : value + ' days';

        modals.show(`
            <div class="modal-header">
                <h2 class="modal-title">Cleanup Preview</h2>
                <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('close')}</button>
            </div>
            <div class="modal-body">
                <div class="cleanup-preview-summary mb-4">
                    <div class="cleanup-summary-icon">
                        ${components.icon('trash-2', 32)}
                    </div>
                    <div class="cleanup-summary-text">
                        <div class="cleanup-summary-count">${totalItems} items</div>
                        <div class="cleanup-summary-label">would be removed based on current settings</div>
                    </div>
                </div>
                <div class="cleanup-preview-breakdown">
                    ${previewData.map(d => `
                        <div class="cleanup-preview-row">
                            <div class="cleanup-preview-category">
                                <span class="category-name">${d.category}</span>
                                <span class="category-retention">Older than ${formatRetention(d.retention)}</span>
                            </div>
                            <div class="cleanup-preview-count ${d.count === 0 ? 'zero' : ''}">${d.count} items</div>
                        </div>
                    `).join('')}
                </div>
            </div>
            <div class="modal-footer">
                <button class="btn btn-secondary" onclick="modals.close()">Close</button>
                <button class="btn btn-primary" onclick="handlers.runRetentionCleanup(); modals.close();">
                    ${components.icon('trash-2', 14)} Run Cleanup
                </button>
            </div>
        `);
    },

    runRetentionCleanup: async function() {
        const confirmed = await modals.confirm(
            'This will permanently delete data older than your retention settings. This cannot be undone.',
            { title: 'Run Data Cleanup?', confirmText: 'Run Cleanup', danger: true }
        );

        if (!confirmed) return;

        toast.success('Cleanup started...');

        // Simulate cleanup process
        await new Promise(resolve => setTimeout(resolve, 1500));

        // Mock cleanup results
        const cleanedItems = Math.floor(Math.random() * 50) + 10;
        const freedSpace = (Math.random() * 10 + 1).toFixed(1);

        toast.success(`Cleanup complete! Removed ${cleanedItems} items, freed ${freedSpace}MB`);
    },

