    exportUserData: async function() {
        toast.info('Preparing your data export...');
        try {
            const data = {
                exportDate: new Date().toISOString(),
                version: '1.0',
                user: { ...(store.state.user || {}), password: undefined },
                inventory: store.state.inventory || [],
                listings: store.state.listings || [],
                orders: store.state.orders || [],
                offers: store.state.offers || [],
                sales: store.state.sales || [],
                transactions: store.state.transactions || [],
                checklists: store.state.checklists || [],
                calendarEvents: store.state.calendarEvents || [],
                shops: store.state.shops || [],
                automations: store.state.automations || [],
            };
            const json = JSON.stringify(data, null, 2);
            const blob = new Blob([json], { type: 'application/json' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `vaultlister-export-${toLocalDate(new Date())}.json`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
            toast.success('Data export downloaded successfully');
        } catch (error) {
            toast.error('Failed to export data: ' + error.message);
        }
    },

