    addFeedbackResponse: async function(event, feedbackId) {
        event.preventDefault();
        const input = document.getElementById('feedback-response-input');
        const message = input.value.trim();
        if (!message) return;

        try {
            await api.ensureCSRFToken();
            await api.post('/feedback/' + feedbackId + '/responses', { message });
            toast.success('Response added!');
            // Refresh the detail modal
            handlers.showFeedbackDetail(feedbackId);
        } catch (error) {
            console.error('Error adding response:', error);
            toast.error(error.message || 'Failed to add response');
        }
    },

    handleScreenshotUpload: function(event) {
        const file = event.target.files[0];
        if (!file) return;

        if (file.size > 2 * 1024 * 1024) {
            toast.error('Screenshot too large. Maximum size is 2MB.');
            event.target.value = '';
            return;
        }

        const validTypes = ['image/png', 'image/jpeg', 'image/gif', 'image/webp'];
        if (!validTypes.includes(file.type)) {
            toast.error('Invalid file type. Use PNG, JPEG, GIF, or WebP.');
            event.target.value = '';
            return;
        }

        const reader = new FileReader();
        reader.onload = function(e) {
            const base64 = e.target.result.split(',')[1];
            store.setState({
                feedbackScreenshot: e.target.result,
                feedbackScreenshotData: base64,
                feedbackScreenshotMime: file.type
            });
            // Re-render the screenshot section
            const dropZone = document.getElementById('screenshot-drop-zone');
            if (dropZone) {
                dropZone.innerHTML = `
                    <div style="position: relative; display: inline-block;">
                        <img src="${e.target.result}" style="max-width: 300px; max-height: 200px; border-radius: 4px;" alt="Screenshot preview">
                        <button type="button" onclick="event.stopPropagation(); handlers.clearScreenshot();" style="position: absolute; top: -8px; right: -8px; background: var(--danger-600); color: white; border: none; border-radius: 50%; width: 24px; height: 24px; font-size: 14px; cursor: pointer; display: flex; align-items: center; justify-content: center;">x</button>
                    </div>
                `;
            }
        };
        reader.readAsDataURL(file);
    },

    clearScreenshot: function() {
        store.setState({
            feedbackScreenshot: null,
            feedbackScreenshotData: null,
            feedbackScreenshotMime: null
        });
        const input = document.getElementById('screenshot-input');
        if (input) input.value = '';
        const dropZone = document.getElementById('screenshot-drop-zone');
        if (dropZone) {
            dropZone.innerHTML = `
                <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="var(--gray-400)" stroke-width="2" style="margin-bottom: 8px;">
                    <rect x="3" y="3" width="18" height="18" rx="2" ry="2"></rect>
                    <circle cx="8.5" cy="8.5" r="1.5"></circle>
                    <polyline points="21 15 16 10 5 21"></polyline>
                </svg>
                <p style="margin: 0; color: var(--gray-500); font-size: 14px;">Click to upload a screenshot</p>
                <p style="margin: 4px 0 0 0; color: var(--gray-400); font-size: 12px;">PNG, JPEG, GIF, or WebP (max 2MB)</p>
            `;
        }
    },

