    crosslistSelected: async function() {
        const ids = store.state.selectedItems;
        if (ids.length === 0) return toast.warning('No items selected');
        modals.crosslistItems(ids);
    },

    submitCrosslist: async function(event, itemIds) {
        event.preventDefault();
        const form = event.target;
        const formData = new FormData(form);
        const selectedPlatforms = formData.getAll('platforms');
        const priceAdjust = parseFloat(formData.get('priceAdjust') || 0);

        if (selectedPlatforms.length === 0) {
            return toast.warning('Please select at least one platform');
        }

        const ids = itemIds.split(',');
        const submitBtn = form.querySelector('.btn-primary') || form.querySelector('button[type="submit"]');
        loadingState.setButton(submitBtn, true);

        try {
            await api.ensureCSRFToken();
            await api.post('/listings/crosslist', {
                itemIds: ids,
                platforms: selectedPlatforms,
                priceAdjustment: priceAdjust
            });

            toast.success(`${ids.length} item(s) cross-listed to ${selectedPlatforms.length} platform(s)`);
            loadingState.setButton(submitBtn, false);
            modals.close();
            await handlers.loadListings();
            store.setState({ selectedItems: [] });
        } catch (error) {
            loadingState.setButton(submitBtn, false);
            // Retry once if CSRF error
            if (error.message && error.message.includes('CSRF')) {
                try {
                    loadingState.setButton(submitBtn, true);
                    await api.ensureCSRFToken(true); // Force refresh token
                    await api.post('/listings/crosslist', {
                        itemIds: ids,
                        platforms: selectedPlatforms,
                        priceAdjustment: priceAdjust
                    });

                    toast.success(`${ids.length} item(s) cross-listed to ${selectedPlatforms.length} platform(s)`);
                    loadingState.setButton(submitBtn, false);
                    modals.close();
                    await handlers.loadListings();
                    store.setState({ selectedItems: [] });
                } catch (retryError) {
                    loadingState.setButton(submitBtn, false);
                    toast.error('CSRF validation failed. Please refresh the page and try again.');
                }
            } else {
                toast.error(error.message);
            }
        }
    },

    // Delete single item,

    deleteItem: async function(itemId) {
        const item = store.state.inventory.find(i => i.id === itemId);
        const itemTitle = item ? item.title : 'this item';

        if (!await modals.confirm(`Delete "${itemTitle}"?`, { title: 'Delete Item', confirmText: 'Delete', danger: true })) return;

        try {
            await api.delete(`/inventory/${itemId}`);
            toast.success('Item deleted successfully');
            await handlers.loadInventory();

            // Re-render inventory page if currently viewing it
            if (store.state.currentPage === 'inventory') {
                const pageContent = pages.inventory();
                document.querySelector('.page-content').innerHTML = pageContent;
            }
        } catch (error) {
            toast.error(error.message);
        }
    },

    _setBulkLoading: function(loading) {
        const bar = document.getElementById('selection-menu');
        if (!bar) return;
        const btns = bar.querySelectorAll('.bulk-action-btn');
        btns.forEach(btn => { btn.disabled = loading; btn.style.opacity = loading ? '0.5' : '1'; });
        const countEl = bar.querySelector('.bulk-actions-count');
        if (countEl && loading) {
            countEl.dataset.origText = countEl.textContent;
            countEl.innerHTML = '<span class="spinner sm"></span> Processing...';
        } else if (countEl && countEl.dataset.origText) {
            countEl.textContent = countEl.dataset.origText;
        }
    },

    deleteSelected: async function() {
        const ids = store.state.selectedItems;
        if (ids.length === 0) return toast.warning('No items selected');

        if (!await modals.confirm(`Delete ${ids.length} item(s)?`, { title: 'Delete Items', confirmText: 'Delete All', danger: true })) return;

        handlers._setBulkLoading(true);
        try {
            await api.post('/inventory/bulk', { action: 'delete', ids });
            toast.success(`${ids.length} item(s) deleted`);
            store.setState({ selectedItems: [] });
            await handlers.loadInventory();

            if (store.state.currentPage === 'inventory') {
                const pageContent = pages.inventory();
                document.querySelector('.page-content').innerHTML = pageContent;
            }

            const menu = document.getElementById('selection-menu');
            if (menu) menu.classList.add('hidden');
        } catch (error) {
            toast.error(error.message);
        } finally {
            handlers._setBulkLoading(false);
        }
    },

