    importOrdersCSV: async function(event) {
        const file = event.target.files[0];
        if (!file) return;

        try {
            const text = await file.text();
            const lines = text.split('\\n');
            if (lines.length === 0) {
                toast.error('File is empty');
                return;
            }
            const headers = lines[0].split(',').map(h => h.trim().toLowerCase());

            const orders = [];
            for (let i = 1; i < lines.length; i++) {
                if (!lines[i].trim()) continue;
                const values = lines[i].split(',').map(v => v.trim().replace(/^"|"$/g, ''));
                const order = {};
                headers.forEach((h, idx) => {
                    order[h] = values[idx] || '';
                });
                orders.push(order);
            }

            toast.success(`Imported ${orders.length} orders from CSV`);
            modals.close();

            // If auto-label is enabled, prompt for label generation
            if (store.state.autoGenerateLabels && orders.length > 0) {
                setTimeout(() => {
                    modals.confirm('Auto-generate shipping labels for ' + orders.length + ' imported orders?', { title: 'Generate Labels', confirmText: 'Generate' }).then(confirmed => {
                        if (confirmed) {
                            handlers.generateLabelsForOrders(orders);
                        }
                    });
                }, 500);
            }

            // Reload orders
            await handlers.loadOrders();
            if (store.state.currentPage === 'orders') {
                renderApp(pages.orders());
            }
        } catch (error) {
            toast.error('Failed to import CSV: ' + error.message);
        }
    },

    syncAllPlatformOrders: async function() {
        toast.info('Syncing orders from all connected platforms...');

        try {
            await api.ensureCSRFToken();
            const result = await api.post('/orders/sync-all');
            toast.success(result.message || 'Orders synced successfully');

            // If auto-label is enabled and new orders found
            if (store.state.autoGenerateLabels && result.newOrders > 0) {
                setTimeout(() => {
                    modals.confirm('Auto-generate shipping labels for ' + result.newOrders + ' new orders?', { title: 'Generate Labels', confirmText: 'Generate' }).then(confirmed => {
                        if (confirmed) {
                            handlers.showBulkLabelModal();
                        }
                    });
                }, 500);
            }

            await handlers.loadOrders();
            if (store.state.currentPage === 'orders') {
                renderApp(pages.orders());
            }
        } catch (error) {
            toast.error('Failed to sync orders: ' + error.message);
        }
    },

    syncPlatformOrders: async function(platform) {
        toast.info('Syncing orders from ' + platform + '...');

        try {
            await api.ensureCSRFToken();
            const result = await api.post('/orders/sync/' + platform);
            toast.success(result.message || 'Orders synced from ' + platform);
            await handlers.loadOrders();
            if (store.state.currentPage === 'orders') {
                renderApp(pages.orders());
            }
        } catch (error) {
            toast.error('Failed to sync ' + platform + ' orders: ' + error.message);
        }
    },

