    updateServiceTypeOptions: function(carrier, mode) {
        const serviceTypes = {
            'USPS': ['Priority Mail', 'First Class', 'Parcel Select', 'Media Mail', 'Priority Express'],
            'UPS': ['Ground', 'Next Day Air', '2nd Day Air', '3 Day Select'],
            'FedEx': ['Ground', 'Express Saver', '2Day', 'Standard Overnight', 'Priority Overnight'],
            'DHL': ['Express Worldwide', 'Express', 'Economy Select'],
            'Other': ['Standard', 'Expedited', 'Economy']
        };

        const selectId = mode === 'add' ? 'add-service-type' : 'edit-service-type';
        const select = document.getElementById(selectId);
        if (!select) return;

        if (!carrier || !serviceTypes[carrier]) {
            select.innerHTML = '<option value="">Select carrier first</option>';
            return;
        }

        select.innerHTML = '<option value="">Select Service</option>' +
            serviceTypes[carrier].map(s => `<option value="${s}">${s}</option>`).join('');
    },

    addShippingProfile: async function(event) {
        event.preventDefault();
        const form = event.target;
        const formData = new FormData(form);

        const profileData = {
            name: formData.get('name'),
            carrier: formData.get('carrier') || null,
            serviceType: formData.get('serviceType') || null,
            packageType: formData.get('packageType') || null,
            weightOz: parseFloat(formData.get('weightOz')) || 0,
            length: parseFloat(formData.get('length')) || 0,
            width: parseFloat(formData.get('width')) || 0,
            height: parseFloat(formData.get('height')) || 0,
            handlingTimeDays: parseInt(formData.get('handlingTimeDays')) || 1,
            domesticCost: parseFloat(formData.get('domesticCost')) || 0,
            internationalCost: parseFloat(formData.get('internationalCost')) || null,
            freeShippingThreshold: parseFloat(formData.get('freeShippingThreshold')) || null,
            platforms: formData.getAll('platforms'),
            notes: formData.get('notes') || null,
            isDefault: formData.get('isDefault') === 'on'
        };

        try {
            await api.ensureCSRFToken();
            await api.post('/shipping-profiles', profileData);

            toast.success('Shipping profile created!');
            modals.close();
            await this.loadShippingProfiles();

            if (store.state.currentPage === 'shipping-profiles') {
                const pageContent = pages.shippingProfiles();
                document.querySelector('.page-content').innerHTML = pageContent;
            }
        } catch (error) {
            toast.error('Failed to create profile: ' + error.message);
        }
    },

