    // Show analytics customization modal,

    showAnalyticsCustomization: function() {
        const currentTab = store.state.analyticsTab || 'graphs';
        const analyticsSettings = store.state.analyticsSettings || {
            graphs: { showRevenue: true, showProfit: true, showSales: true, chartType: 'line' },
            performance: { showComparisons: true, showTrends: true, showBreakdowns: true },
            heatmaps: { showDayHour: true, showPlatform: true, showCategory: true },
            predictions: { showForecast: true, showBestTimes: true, showTrending: true, showPricing: true },
            reports: { autoGenerate: false, includeCharts: true },
            'ratio-analysis': { showLiquidity: true, showEfficiency: true, showProfitability: true },
            profitability: { showMargins: true, showTrends: true, showComparison: true },
            'product-analysis': { showTopSellers: true, showCategories: true, showInventory: true }
        };

        const currentSettings = analyticsSettings[currentTab] || {};

        modals.show(`
            <div class="modal-header">
                <h2 class="modal-title">${components.icon('settings', 20)} Customize Analytics - ${currentTab.charAt(0).toUpperCase() + currentTab.slice(1).replace('-', ' ')}</h2>
                <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('close')}</button>
            </div>
            <div class="modal-body">
                <form onsubmit="handlers.saveAnalyticsSettings(event, '${currentTab}')">
                    <div class="mb-4">
                        <h4 class="font-medium mb-3">Display Options</h4>
                        ${Object.entries(currentSettings).map(([key, value]) => `
                            <label class="flex items-center gap-3 mb-2 cursor-pointer">
                                <input type="checkbox" name="${key}" ${value ? 'checked' : ''} class="form-checkbox">
                                <span>${key.replace(/([A-Z])/g, ' $1').replace(/^./, s => s.toUpperCase())}</span>
                            </label>
                        `).join('')}
                    </div>
                    <div class="mb-4">
                        <h4 class="font-medium mb-3">Visible Tabs</h4>
                        ${['Graphs', 'Performance', 'Heatmaps', 'Predictions', 'Reports', 'Ratio Analysis', 'Profitability Analysis', 'Product Analysis'].map(tab => {
                            const tabId = tab.toLowerCase().replace(/ /g, '-');
                            const hiddenTabs = store.state.hiddenAnalyticsTabs || [];
                            return `
                                <label class="flex items-center gap-3 mb-2 cursor-pointer">
                                    <input type="checkbox" name="tab_${tabId}" ${!hiddenTabs.includes(tabId) ? 'checked' : ''} class="form-checkbox">
                                    <span>${tab}</span>
                                </label>
                            `;
                        }).join('')}
                    </div>
                    <div class="flex justify-end gap-2 mt-6">
                        <button type="button" class="btn btn-secondary" onclick="modals.close()">Cancel</button>
                        <button type="submit" class="btn btn-primary">${components.icon('save', 16)} Save Settings</button>
                    </div>
                </form>
            </div>
        `);
    },

    // Save analytics customization settings,

    saveAnalyticsSettings: function(event, tab) {
        event.preventDefault();
        const form = event.target;
        const formData = new FormData(form);

        // Save tab settings
        const analyticsSettings = { ...(store.state.analyticsSettings || {}) };
        analyticsSettings[tab] = {};

        // Get display options (non-tab checkboxes)
        for (const [key, value] of formData.entries()) {
            if (!key.startsWith('tab_')) {
                analyticsSettings[tab][key] = value === 'on';
            }
        }

        // Get hidden tabs
        const hiddenTabs = [];
        const allTabs = ['graphs', 'performance', 'heatmaps', 'predictions', 'reports', 'ratio-analysis', 'profitability-analysis', 'product-analysis'];
        allTabs.forEach(tabId => {
            if (!formData.has(`tab_${tabId}`)) {
                hiddenTabs.push(tabId);
            }
        });

        store.setState({ analyticsSettings, hiddenAnalyticsTabs: hiddenTabs });

        // Save to localStorage
        localStorage.setItem('vaultlister_analytics_settings', JSON.stringify(analyticsSettings));
        localStorage.setItem('vaultlister_hidden_analytics_tabs', JSON.stringify(hiddenTabs));

        toast.success('Analytics settings saved');
        modals.close();
        renderApp(pages.analytics());
    },

