    switchChartType: function(chartId, type) {
        const chartDisplayModes = { ...store.state.chartDisplayModes, [chartId]: type };
        store.setState({ chartDisplayModes });
        if (store.state.currentPage === 'analytics') {
            renderApp(pages.analytics());
        }
    },

