    // Insert pattern token at cursor position in pattern input,

    insertPatternToken: function(token) {
        const input = document.querySelector('input[name="pattern"]');
        if (!input) return;

        const start = input.selectionStart;
        const end = input.selectionEnd;
        const value = input.value;

        input.value = value.substring(0, start) + token + value.substring(end);
        input.focus();
        input.setSelectionRange(start + token.length, start + token.length);

        // Trigger live preview
        handlers.livePreviewSkuPattern(input.value);
    },

    // Live preview SKU pattern while typing,

    livePreviewSkuPattern: async function(pattern) {
        if (!pattern) {
            const previewEl = document.getElementById('sku-live-preview');
            if (previewEl) previewEl.style.display = 'none';
            return;
        }

        try {
            const previewSku = await handlers.previewSkuPattern(pattern);
            const previewEl = document.getElementById('sku-live-preview');
            const valueEl = document.getElementById('sku-preview-value');

            if (previewEl && valueEl && previewSku) {
                previewEl.style.display = 'flex';
                valueEl.textContent = previewSku;
            }
        } catch (error) {
            console.error('Preview error:', error);
        }
    },

    // Execute batch SKU update from modal,

    executeBatchSkuUpdate: function() {
        const ruleSelect = document.getElementById('batch-sku-rule-select');
        const scopeRadio = document.querySelector('input[name="batchScope"]:checked');

        if (!ruleSelect || !ruleSelect.value) {
            toast.error('Please select a rule');
            return;
        }

        const ruleId = ruleSelect.value;
        const onlyEmpty = scopeRadio?.value !== 'all';

        handlers.batchUpdateSkus(ruleId, onlyEmpty);
    },

