    // Update receipt data,

    updateReceipt: async function(event) {
        event.preventDefault();
        const form = event.target;
        const formData = new FormData(form);
        const receiptId = formData.get('receiptId');

        // Build updated data from form
        const parsedData = {
            receiptType: formData.get('receiptType'),
            vendor: {
                name: formData.get('vendorName'),
                address: formData.get('vendorAddress'),
                phone: formData.get('vendorPhone')
            },
            date: formData.get('date'),
            subtotal: parseFloat(formData.get('subtotal')) || 0,
            tax: parseFloat(formData.get('tax')) || 0,
            shipping: parseFloat(formData.get('shipping')) || 0,
            discount: parseFloat(formData.get('discount')) || 0,
            total: parseFloat(formData.get('total')) || 0,
            paymentMethod: formData.get('paymentMethod'),
            orderNumber: formData.get('orderNumber')
        };

        // Parse line items from form
        const itemRows = document.querySelectorAll('.receipt-line-item-row');
        parsedData.items = Array.from(itemRows).map(row => ({
            description: row.querySelector('[name="itemDescription"]')?.value || '',
            quantity: parseInt(row.querySelector('[name="itemQty"]')?.value) || 1,
            unitPrice: parseFloat(row.querySelector('[name="itemUnitPrice"]')?.value) || 0,
            total: parseFloat(row.querySelector('[name="itemTotal"]')?.value) || 0,
            inventoryId: row.querySelector('[name="inventoryLink"]')?.value || null
        }));

        try {
            await api.ensureCSRFToken();
            await api.put(`/receipts/${receiptId}`, { parsedData });
            toast.success('Receipt updated');
            await handlers.loadReceiptQueue();
            modals.close();
        } catch (error) {
            toast.error('Failed to update receipt: ' + error.message);
        }
    },

    // Process receipt (convert to purchase/sale/expense),

    processReceipt: async function(receiptId) {
        try {
            await api.ensureCSRFToken();
            const result = await api.post(`/receipts/${receiptId}/process`);

            let message = 'Receipt processed';
            if (result.purchaseId) message = 'Purchase created from receipt';
            else if (result.transactionId) message = 'Transaction created from receipt';

            toast.success(message);
            await handlers.loadReceiptQueue();
            modals.close();

            // Reload relevant data
            if (result.purchaseId) {
                await handlers.loadFinancials();
            }
        } catch (error) {
            toast.error('Failed to process receipt: ' + error.message);
        }
    },

