    // Load connected email accounts,

    connectGmail: async function() {
        try {
            store.setState({ emailConnecting: true });

            // Get authorization URL from backend
            const response = await api.get('/email/oauth/authorize');
            const { authUrl, state } = response;

            // Open popup window for OAuth flow
            const width = 600;
            const height = 700;
            const left = window.screen.width / 2 - width / 2;
            const top = window.screen.height / 2 - height / 2;

            const popup = window.open(
                authUrl,
                'gmail_oauth_popup',
                `width=${width},height=${height},left=${left},top=${top},toolbar=no,menubar=no,location=no,status=no`
            );

            if (!popup) {
                toast.error('Popup blocked - please allow popups for Gmail connection');
                store.setState({ emailConnecting: false });
                return;
            }

            // Show loading toast
            toast.info('Connecting to Gmail...');

            // Listen for OAuth callback via postMessage
            const handleMessage = async (event) => {
                if (event.origin !== window.location.origin) return;
                if (event.data && event.data.type === 'email-oauth-success') {
                    window.removeEventListener('message', handleMessage);
                    store.setState({ emailConnecting: false });
                    toast.success(`Gmail connected: ${event.data.email}`);
                    await handlers.loadEmailAccounts();

                    // Refresh Receipt Parser page if currently viewing it
                    if (store.state.currentPage === 'receipt-parser') {
                        const pageContent = pages.receiptParser();
                        const pageElement = document.querySelector('.page-content');
                        if (pageElement) {
                            pageElement.innerHTML = pageContent;
                        }
                    }
                } else if (event.data && event.data.type === 'email-oauth-error') {
                    window.removeEventListener('message', handleMessage);
                    store.setState({ emailConnecting: false });
                    toast.error(`Gmail connection failed: ${event.data.error}`);
                }
            };

            window.addEventListener('message', handleMessage);

            // Timeout after 5 minutes
            setTimeout(() => {
                window.removeEventListener('message', handleMessage);
                if (store.state.emailConnecting) {
                    store.setState({ emailConnecting: false });
                    toast.error('Gmail connection timed out');
                }
            }, 5 * 60 * 1000);

        } catch (error) {
            console.error('Gmail OAuth error:', error);
            store.setState({ emailConnecting: false });
            toast.error('Failed to initiate Gmail connection');
        }
    },

    // Disconnect email account,

    disconnectEmailAccount: async function(accountId) {
        if (!await modals.confirm('Disconnect this email account? Email syncing will stop.', { title: 'Disconnect Email', confirmText: 'Disconnect', danger: true })) return;

        try {
            await api.ensureCSRFToken();
            await api.delete(`/email/accounts/${accountId}`);
            toast.success('Email account disconnected');
            await handlers.loadEmailAccounts();

            // Refresh Receipt Parser page if currently viewing it
            if (store.state.currentPage === 'receipt-parser') {
                const pageContent = pages.receiptParser();
                const pageElement = document.querySelector('.page-content');
                if (pageElement) {
                    pageElement.innerHTML = pageContent;
                }
            }
        } catch (error) {
            console.error('Failed to disconnect email account:', error);
            toast.error('Failed to disconnect email account');
        }
    },

    // Sync receipts from email account,

    syncEmailAccount: async function(accountId) {
        try {
            await api.ensureCSRFToken();
            const result = await api.post(`/email/accounts/${accountId}/sync`);
            toast.success(`Syncing receipts from email...`);

            // Update account sync status
            const accounts = store.state.emailAccounts.map(acc => {
                if (acc.id === accountId) {
                    return { ...acc, sync_status: 'syncing' };
                }
                return acc;
            });
            store.setState({ emailAccounts: accounts });

            // Poll for sync completion
            let attempts = 0;
            const maxAttempts = 60; // 1 minute timeout (60 * 1 second)

            const pollSync = setInterval(async () => {
                attempts++;
                try {
                    const statusResult = await api.get(`/email/accounts/${accountId}`);
                    const account = statusResult.account;

                    if (account && account.sync_status !== 'syncing') {
                        clearInterval(pollSync);
                        await handlers.loadEmailAccounts();

                        if (account.sync_status === 'completed') {
                            toast.success(`Synced ${account.last_sync_count || 0} receipts from email`);
                            // Reload receipt queue
                            await handlers.loadReceiptQueue();
                        } else if (account.sync_status === 'failed') {
                            toast.error(`Email sync failed: ${account.sync_error || 'Unknown error'}`);
                        }

                        // Refresh Receipt Parser page if currently viewing it
                        if (store.state.currentPage === 'receipt-parser') {
                            const pageContent = pages.receiptParser();
                            const pageElement = document.querySelector('.page-content');
                            if (pageElement) {
                                pageElement.innerHTML = pageContent;
                            }
                        }
                    }

                    if (attempts >= maxAttempts) {
                        clearInterval(pollSync);
                        await handlers.loadEmailAccounts();
                        toast.warning('Email sync is taking longer than expected, but will continue in background');
                    }
                } catch (error) {
                    if (attempts >= maxAttempts) {
                        clearInterval(pollSync);
                        console.error('Sync polling timeout:', error);
                    }
                }
            }, 1000);

        } catch (error) {
            console.error('Failed to sync email account:', error);
            toast.error('Failed to sync email account: ' + error.message);
        }
    },

