    createRelistingRule: async function() {
        const name = document.getElementById('rr-name')?.value?.trim();
        if (!name) { toast.error('Rule name is required'); return; }

        try {
            await api.ensureCSRFToken();
            await api.post('/relisting/rules', {
                name,
                stale_days: parseInt(document.getElementById('rr-stale-days')?.value) || 30,
                price_strategy: document.getElementById('rr-strategy')?.value || 'fixed',
                price_reduction_amount: parseFloat(document.getElementById('rr-reduction')?.value) || 5,
                price_floor_percentage: parseInt(document.getElementById('rr-floor')?.value) || 50,
                auto_relist: document.getElementById('rr-auto-relist')?.checked || false
            });
            document.getElementById('relisting-rule-modal')?.remove();
            toast.success('Relisting rule created');
            await handlers.loadRelistingData();
            renderApp(pages.smartRelisting());
        } catch (e) {
            toast.error('Failed to create rule: ' + e.message);
        }
    },

