    createLabel: async function() {
        const toName = document.getElementById('sl-to-name')?.value?.trim();
        if (!toName) { toast.error('Recipient name is required'); return; }

        try {
            await api.ensureCSRFToken();
            await api.post('/shipping-labels-mgmt/', {
                carrier: document.getElementById('sl-carrier')?.value || 'usps',
                service_type: document.getElementById('sl-service')?.value || '',
                weight_oz: parseFloat(document.getElementById('sl-weight')?.value) || null,
                length_in: parseFloat(document.getElementById('sl-length')?.value) || null,
                width_in: parseFloat(document.getElementById('sl-width')?.value) || null,
                height_in: parseFloat(document.getElementById('sl-height')?.value) || null,
                from_name: document.getElementById('sl-from-name')?.value || '',
                from_street1: document.getElementById('sl-from-street1')?.value || '',
                from_city: document.getElementById('sl-from-city')?.value || '',
                from_state: document.getElementById('sl-from-state')?.value || '',
                from_zip: document.getElementById('sl-from-zip')?.value || '',
                to_name: toName,
                to_street1: document.getElementById('sl-to-street1')?.value || '',
                to_city: document.getElementById('sl-to-city')?.value || '',
                to_state: document.getElementById('sl-to-state')?.value || '',
                to_zip: document.getElementById('sl-to-zip')?.value || '',
                to_email: document.getElementById('sl-to-email')?.value || ''
            });
            document.getElementById('create-label-modal')?.remove();
            toast.success('Shipping label created');
            await handlers.loadShippingLabelsData();
            renderApp(pages.shippingLabelsPage());
        } catch (e) {
            toast.error('Failed to create label: ' + e.message);
        }
    },

    showRateShoppingModal: function() {
        const modal = document.createElement('div');
        modal.className = 'modal-overlay';
        modal.id = 'rate-shopping-modal';
        modal.innerHTML = `
            <div class="modal" style="max-width:550px;">
                <div class="modal-header">
                    <h3>Compare Shipping Rates</h3>
                    <button class="btn btn-ghost" onclick="document.getElementById('rate-shopping-modal').remove()">&#10005;</button>
                </div>
                <div class="modal-body">
                    <div style="display:grid; grid-template-columns:1fr 1fr; gap:12px;">
                        <div class="form-group"><label class="form-label">Weight (oz) *</label><input type="number" id="rs-weight" class="form-input" value="16" step="0.1"></div>
                        <div class="form-group"><label class="form-label">From ZIP *</label><input type="text" id="rs-from-zip" class="form-input" placeholder="10001"></div>
                        <div class="form-group"><label class="form-label">To ZIP *</label><input type="text" id="rs-to-zip" class="form-input" placeholder="90001"></div>
                    </div>
                    <div id="rs-results" class="mt-4"></div>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-ghost" onclick="document.getElementById('rate-shopping-modal').remove()">Close</button>
                    <button class="btn btn-primary" onclick="handlers.fetchRates()">Get Rates</button>
                </div>
            </div>
        `;
        document.body.appendChild(modal);
    },

    fetchRates: async function() {
        const resultsEl = document.getElementById('rs-results');
        if (!resultsEl) return;
        resultsEl.innerHTML = '<div class="text-center py-4">Loading rates...</div>';

        try {
            const data = await api.post('/shipping-labels-mgmt/rates', {
                weight_oz: parseFloat(document.getElementById('rs-weight')?.value) || 16,
                from_zip: document.getElementById('rs-from-zip')?.value || '',
                to_zip: document.getElementById('rs-to-zip')?.value || ''
            });

            resultsEl.innerHTML = `
                <div class="table-container">
                    <table class="table table-sm">
                        <thead><tr><th>Carrier</th><th>Service</th><th>Rate</th><th>Days</th></tr></thead>
                        <tbody>
                            ${(data.rates || []).map(r => `
                                <tr>
                                    <td><span class="badge">${r.carrier.toUpperCase()}</span></td>
                                    <td>${escapeHtml(r.service)}</td>
                                    <td class="font-medium">$${r.rate.toFixed(2)}</td>
                                    <td>${r.delivery_days}d</td>
                                </tr>
                            `).join('')}
                        </tbody>
                    </table>
                </div>
            `;
        } catch (e) {
            resultsEl.innerHTML = '<div class="text-error">Failed to fetch rates</div>';
        }
    },

