    // ============================================
    // Custom Reports Handlers
    // ============================================,

    createReport: function() {
        store.setState({
            editingReport: { name: '', description: '', widgets: [], date_range: '30d' }
        });
        renderApp(pages.reports());
    },

    editReport: async function(reportId) {
        const report = (store.state.customReports || []).find(r => r.id === reportId);
        if (report) {
            store.setState({ editingReport: { ...report } });
            renderApp(pages.reports());
        }
    },

    viewReport: async function(reportId) {
        try {
            const data = await api.get(`/reports/${reportId}`);
            store.setState({ viewingReport: data.report, reportWidgetData: data.widgetData });
            modals.viewReport(data.report, data.widgetData);
        } catch (e) {
            toast.error('Failed to load report');
        }
    },

    addReportWidget: function(type, label, size) {
        const report = store.state.editingReport;
        if (!report) return;
        const widgets = [...(report.widgets || []), { type, label, size, id: 'w-' + Date.now() }];
        store.setState({ editingReport: { ...report, widgets } });
        renderApp(pages.reports());
    },

    removeReportWidget: function(index) {
        const report = store.state.editingReport;
        if (!report) return;
        const widgets = [...(report.widgets || [])];
        widgets.splice(index, 1);
        store.setState({ editingReport: { ...report, widgets } });
        renderApp(pages.reports());
    },

    saveReport: async function() {
        const report = store.state.editingReport;
        if (!report) return;

        const name = document.getElementById('report-name')?.value?.trim();
        const description = document.getElementById('report-description')?.value?.trim();
        const date_range = document.getElementById('report-date-range')?.value || '30d';

        if (!name) {
            toast.error('Report name is required');
            return;
        }

        const reportData = {
            name,
            description,
            widgets: report.widgets || [],
            date_range
        };

        try {
            await api.ensureCSRFToken();
            if (report.id) {
                await api.put(`/reports/${report.id}`, reportData);
                toast.success('Report updated');
            } else {
                await api.post('/reports', reportData);
                toast.success('Report created');
            }
            store.setState({ editingReport: null });
            await handlers.loadReportsData();
            renderApp(pages.reports());
        } catch (e) {
            toast.error('Failed to save report: ' + e.message);
        }
    },

    deleteReport: async function(reportId) {
        if (!await modals.confirm('Delete this report?', { title: 'Delete Report', confirmText: 'Delete', danger: true })) return;
        try {
            await api.ensureCSRFToken();
            await api.delete(`/reports/${reportId}`);
            toast.success('Report deleted');
            await handlers.loadReportsData();
            renderApp(pages.reports());
        } catch (e) {
            toast.error('Failed to delete report');
        }
    },

    // ============================================
    // Print Shipping Labels Handler
    // ============================================,

    printShippingLabels: async function(labelIds) {
        if (!labelIds || labelIds.length === 0) {
            toast.error('No labels selected');
            return;
        }
        try {
            await api.ensureCSRFToken();
            const result = await api.post('/shipping-labels-mgmt/print-batch', {
                label_ids: labelIds,
                format: 'thermal_4x6'
            });
            toast.success(result.message || 'Labels marked as printed');
            await handlers.loadShippingLabelsData();
            renderApp(pages.shippingLabelsPage());
        } catch (e) {
            toast.error('Failed to mark labels as printed');
        }
    },

    // Generate PDF for multiple shipping labels,

    downloadLabelsPdf: async function(labelIds, format = 'thermal_4x6') {
        if (!labelIds || labelIds.length === 0) {
            toast.error('No labels selected');
            return;
        }
        try {
            toast.info('Generating PDF...');
            await api.ensureCSRFToken();
            const result = await api.post('/shipping-labels-mgmt/generate-pdf', {
                label_ids: labelIds,
                format: format,
                layout: 'single'
            });

            if (result.pdf_data) {
                // Generate PDF on client side using the data
                const pdfData = result.pdf_data;
                const labels = pdfData.labels;

                // Create printable HTML for labels
                const printWindow = window.open('', '_blank');
                printWindow.document.write(`
                    <!DOCTYPE html>
                    <html>
                    <head>
                        <title>Shipping Labels</title>
                        <style>
                            @media print { @page { size: ${format === 'thermal_4x6' ? '4in 6in' : 'letter'}; margin: 0; } }
                            body { font-family: sans-serif; margin: 0; padding: 0; }
                            .label { page-break-after: always; padding: 0.25in; box-sizing: border-box; height: ${format === 'thermal_4x6' ? '6in' : '5.5in'}; }
                            .label:last-child { page-break-after: auto; }
                            .from, .to { margin-bottom: 0.5in; }
                            .barcode { text-align: center; margin: 0.5in 0; font-family: monospace; font-size: 24px; letter-spacing: 4px; }
                            .carrier { text-align: center; font-size: 20px; font-weight: bold; margin-bottom: 0.25in; }
                            h3 { margin: 0 0 0.1in 0; font-size: 10px; color: #666; }
                            p { margin: 0; line-height: 1.4; }
                        </style>
                    </head>
                    <body>
                        ${labels.map(label => `
                            <div class="label">
                                <div class="carrier">${escapeHtml((label.shipping.carrier || '').toUpperCase())} - ${escapeHtml(label.shipping.service || '')}</div>
                                <div class="from">
                                    <h3>FROM:</h3>
                                    <p><strong>${escapeHtml(label.sender.name || '')}</strong></p>
                                    ${label.sender.company ? `<p>${escapeHtml(label.sender.company)}</p>` : ''}
                                    <p>${escapeHtml(label.sender.street1 || '')}</p>
                                    <p>${escapeHtml(label.sender.city || '')}, ${escapeHtml(label.sender.state || '')} ${escapeHtml(label.sender.zip || '')}</p>
                                </div>
                                <div class="to">
                                    <h3>TO:</h3>
                                    <p><strong>${escapeHtml(label.recipient.name || '')}</strong></p>
                                    ${label.recipient.company ? `<p>${escapeHtml(label.recipient.company)}</p>` : ''}
                                    <p>${escapeHtml(label.recipient.street1 || '')}</p>
                                    ${label.recipient.street2 ? `<p>${escapeHtml(label.recipient.street2)}</p>` : ''}
                                    <p>${escapeHtml(label.recipient.city || '')}, ${escapeHtml(label.recipient.state || '')} ${escapeHtml(label.recipient.zip || '')}</p>
                                </div>
                                ${label.shipping.tracking ? `<div class="barcode">${label.shipping.tracking}</div>` : ''}
                                <p style="text-align: center; font-size: 10px; color: #999;">Weight: ${label.shipping.weight || 0} oz | Cost: $${(label.shipping.cost || 0).toFixed(2)}</p>
                            </div>
                        `).join('')}
                    </body>
                    </html>
                `);
                printWindow.document.close();
                printWindow.print();
                toast.success(`Generated ${labels.length} label(s)`);
            }
        } catch (e) {
            toast.error('Failed to generate PDF: ' + e.message);
        }
    },

