    // Filter event item search,

    filterEventItemSearch: function(query) {
        const inventory = store.state.inventory || [];
        const filtered = inventory.filter(item => {
            const searchTerm = query.toLowerCase();
            return (item.title || '').toLowerCase().includes(searchTerm) ||
                   (item.sku || '').toLowerCase().includes(searchTerm) ||
                   (item.brand || '').toLowerCase().includes(searchTerm);
        });

        const listEl = document.getElementById('event-item-list');
        if (listEl) {
            listEl.innerHTML = filtered.length === 0 ?
                '<p class="text-gray-500 text-center py-4">No items found</p>' :
                filtered.slice(0, 20).map(item => `
                    <div class="flex items-center gap-3 p-3 border-b hover:bg-gray-50 cursor-pointer" onclick="handlers.selectEventItem('', '${item.id}')">
                        <div class="w-12 h-12 bg-gray-100 rounded flex items-center justify-center">
                            ${item.images ? '<img src="' + ((() => { try { return JSON.parse(item.images)[0] || ''; } catch { return ''; } })()) + '" class="w-full h-full object-cover rounded" alt="' + escapeHtml(item.title || 'Item image') + '">' : components.icon('image', 20)}
                        </div>
                        <div class="flex-1">
                            <div class="font-medium">${escapeHtml(item.title)}</div>
                            <div class="text-sm text-gray-500">${item.sku || 'No SKU'} • $${(item.list_price || 0).toFixed(2)}</div>
                        </div>
                        <button class="btn btn-sm btn-primary">Add</button>
                    </div>
                `).join('');
        }
    },

    // Select event item,

    selectEventItem: async function(eventId, itemId) {
        const item = store.state.inventory.find(i => i.id === itemId);
        if (!item) {
            toast.error('Item not found');
            return;
        }

        try {
            await api.ensureCSRFToken();
            await api.post(`/whatnot/events/${eventId}/items`, { inventoryId: itemId });
            toast.success('Item added to event!');
            modals.close();
            await handlers.loadWhatnotEvents();
            renderApp();
        } catch (error) {
            toast.error('Failed to add item: ' + error.message);
        }
    },

