    // Subscribe to push notifications,

    subscribePush: async function() {
        try {
            if (!('serviceWorker' in navigator) || !('PushManager' in window)) {
                toast.error('Push notifications not supported in this browser');
                return;
            }

            const registration = await navigator.serviceWorker.ready;
            const subscription = await registration.pushManager.subscribe({
                userVisibleOnly: true,
                applicationServerKey: 'YOUR_VAPID_PUBLIC_KEY'
            });

            await api.post('/push/subscribe', { subscription });
            toast.success('Push notifications enabled!');
            await this.loadPushStatus();
            renderApp();
        } catch (error) {
            toast.error('Failed to enable push notifications: ' + error.message);
        }
    },

    // Unsubscribe from push notifications,

    unsubscribePush: async function() {
        try {
            const registration = await navigator.serviceWorker.ready;
            const subscription = await registration.pushManager.getSubscription();

            if (subscription) {
                await subscription.unsubscribe();
                await api.post('/push/unsubscribe');
            }

            toast.success('Push notifications disabled');
            await this.loadPushStatus();
            renderApp();
        } catch (error) {
            toast.error('Failed to disable push notifications: ' + error.message);
        }
    },

