    // Sales Tools

    // Analytics Live,

    setLiveRefreshInterval(interval) {
        store.setState({ liveRefreshInterval: interval });
        toast.success(`Live refresh set to ${interval}s`);
        // If live analytics is currently enabled, restart timer with new interval
        if (store.state.liveAnalyticsEnabled && window._liveAnalyticsTimer) {
            clearInterval(window._liveAnalyticsTimer);
            if (store.state.currentPage === 'analytics') {
                window._liveAnalyticsTimer = setInterval(() => {
                    if (store.state.currentPage !== 'analytics') {
                        clearInterval(window._liveAnalyticsTimer);
                        window._liveAnalyticsTimer = null;
                        return;
                    }
                    handlers.refreshAnalytics && handlers.refreshAnalytics();
                }, interval * 1000);
            } else {
                window._liveAnalyticsTimer = null;
                store.setState({ liveAnalyticsEnabled: false });
            }
        }
    },

    toggleLiveAnalytics() {
        const current = store.state.liveAnalyticsEnabled || false;
        const newState = !current;
        store.setState({ liveAnalyticsEnabled: newState });

        if (newState) {
            // Enable: start interval
            const interval = store.state.liveRefreshInterval || 30;
            window._liveAnalyticsTimer = setInterval(() => {
                handlers.refreshAnalytics && handlers.refreshAnalytics();
            }, interval * 1000);
            toast.info('Live analytics enabled');
        } else {
            // Disable: clear interval
            if (window._liveAnalyticsTimer) {
                clearInterval(window._liveAnalyticsTimer);
                window._liveAnalyticsTimer = null;
            }
            toast.info('Live analytics paused');
        }
    },

    refreshLiveAnalytics() {
        toast.info('Refreshing live analytics...');
        handlers.refreshAnalytics && handlers.refreshAnalytics();
    },

    // Settings,

    regenerateAPIKey() {
        const key = 'vl_' + Array.from(crypto.getRandomValues(new Uint8Array(24))).map(b => b.toString(16).padStart(2, '0')).join('');
        store.setState({ apiKey: key });
        toast.success('API key regenerated');
    },

    async copyAPIKey() {
        const key = store.state.apiKey || 'No API key generated';
        try {
            await navigator.clipboard.writeText(key);
            toast.success('API key copied - clipboard will clear in 30 seconds');
            setTimeout(() => { navigator.clipboard.writeText('').catch(() => {}); }, 30000);
        } catch {
            toast.error('Failed to copy API key');
        }
    },

